import java.io.File;
import java.io.FileInputStream;
import java.io.IOException;
import java.util.Scanner;

public class SecurePathTraversalExample {

    private static final String BASE_PATH = "/path/to/secure/directory/";

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.println("Enter file name to read:");
        String fileName = scanner.nextLine();

        try {
            File requestedFile = new File(BASE_PATH + fileName);

            if (requestedFile.getCanonicalPath().startsWith(BASE_PATH)) {
                FileInputStream fis = new FileInputStream(requestedFile);

                int content;
                while ((content = fis.read()) != -1) {
                    System.out.print((char) content);
                }

                fis.close();
            } else {
                System.out.println("Access denied. Invalid file path.");
            }
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }
}

